// Vanilla C00PacketLoginStart definition:
public class C00PacketLoginStart implements Packet<INetHandlerLoginServer> {
    private GameProfile profile;

    public C00PacketLoginStart() {}
    public C00PacketLoginStart(GameProfile profileIn) {
        this.profile = profileIn;
    }

    public void readPacketData(PacketBuffer data) throws IOException {
        this.profile = new GameProfile((UUID) null, data.readStringFromBuffer(16));
    }

    public void writePacketData(PacketBuffer data) throws IOException {
        data.writeString(this.profile.getName());  // only sends the name!
    }

    public GameProfile getProfile() {
        return this.profile;
    }
}

// Jigsaw 0.26 - NetHandlerLoginServer receives login start:
public void processLoginStart(C00PacketLoginStart packetIn) {
    GameProfile gameprofile = packetIn.getProfile();
    if (!this.server.isServerInOnlineMode()) {
        // Offline mode: generate UUID from username
        UUID uuid = UUID.nameUUIDFromBytes(("OfflinePlayer:" + gameprofile.getName()).getBytes(Charsets.UTF_8));
        // Module can intercept S02LoginSuccess to replace this UUID
    }
    this.gameProfile = gameprofile;
}

